import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.CuteRReP.js";const p=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"security.md","filePath":"security.md"}'),n={name:"security.md"};function s(o,e,l,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>CodyMaster takes security seriously. Here&#39;s how the skill kit prevents and detects security vulnerabilities.</p><h2 id="built-in-security-skills" tabindex="-1">Built-in Security Skills <a class="header-anchor" href="#built-in-security-skills" aria-label="Permalink to &quot;Built-in Security Skills&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>What it does</th></tr></thead><tbody><tr><td><strong>cm-secret-shield</strong></td><td>Pre-commit secret scanning, repo-wide pattern detection, token lifecycle management</td></tr><tr><td><strong>cm-identity-guard</strong></td><td>Verify git/deploy identity before push — prevents wrong-account deploys</td></tr><tr><td><strong>cm-quality-gate</strong></td><td>Layer 8: XSS scan + Gate 6: Snyk SAST integration</td></tr></tbody></table><h2 id="security-rules-in-code-generation" tabindex="-1">Security Rules in Code Generation <a class="header-anchor" href="#security-rules-in-code-generation" aria-label="Permalink to &quot;Security Rules in Code Generation&quot;">​</a></h2><p>Five skills enforce security patterns when generating or reviewing code:</p><h3 id="cm-execution-—-security-rules" tabindex="-1">cm-execution — Security Rules <a class="header-anchor" href="#cm-execution-—-security-rules" aria-label="Permalink to &quot;cm-execution — Security Rules&quot;">​</a></h3><ul><li><strong>Frontend:</strong> No <code>innerHTML</code> without <code>escapeHtml()</code>, prefer <code>textContent</code>, validate URLs</li><li><strong>Python:</strong> All paths from config/input must use <code>safe_resolve()</code>, no <code>shell=True</code></li><li><strong>Node/Express:</strong> Disable <code>x-powered-by</code>, set body limits, filter prototype pollution</li></ul><h3 id="cm-planning-—-scope-definition" tabindex="-1">cm-planning — Scope Definition <a class="header-anchor" href="#cm-planning-—-scope-definition" aria-label="Permalink to &quot;cm-planning — Scope Definition&quot;">​</a></h3><p>Requires answering: <em>How will dynamic data be rendered?</em> before starting frontend work.</p><h3 id="cm-tdd-—-security-tdd" tabindex="-1">cm-tdd — Security TDD <a class="header-anchor" href="#cm-tdd-—-security-tdd" aria-label="Permalink to &quot;cm-tdd — Security TDD&quot;">​</a></h3><p>Every XSS, path traversal, or injection fix starts with a failing test.</p><h3 id="cm-code-review-—-part-d-security-checklist" tabindex="-1">cm-code-review — Part D: Security Checklist <a class="header-anchor" href="#cm-code-review-—-part-d-security-checklist" aria-label="Permalink to &quot;cm-code-review — Part D: Security Checklist&quot;">​</a></h3><p>Mandatory security pass covering frontend, backend, and general patterns.</p><h3 id="cm-quality-gate-—-automated-scans" tabindex="-1">cm-quality-gate — Automated Scans <a class="header-anchor" href="#cm-quality-gate-—-automated-scans" aria-label="Permalink to &quot;cm-quality-gate — Automated Scans&quot;">​</a></h3><ul><li><strong>Layer 8:</strong> Grep scan for unescaped <code>innerHTML</code> patterns</li><li><strong>Gate 6:</strong> Snyk Code SAST with severity-based gate decisions</li></ul><h2 id="utilities" tabindex="-1">Utilities <a class="header-anchor" href="#utilities" aria-label="Permalink to &quot;Utilities&quot;">​</a></h2><h3 id="sanitize-js-frontend" tabindex="-1">sanitize.js (Frontend) <a class="header-anchor" href="#sanitize-js-frontend" aria-label="Permalink to &quot;sanitize.js (Frontend)&quot;">​</a></h3><p>Shared utility loaded in all HTML pages:</p><ul><li><code>escapeHtml(str)</code> — Prevents DOM XSS in innerHTML</li><li><code>escapeHtmlWithBreaks(str)</code> — Preserves <code>\\n</code> as <code>&lt;br&gt;</code> while escaping HTML</li><li><code>escapeAttr(str)</code> — Prevents attribute injection</li></ul><h3 id="safe-path-py-python" tabindex="-1">safe_path.py (Python) <a class="header-anchor" href="#safe-path-py-python" aria-label="Permalink to &quot;safe_path.py (Python)&quot;">​</a></h3><p>Path traversal prevention:</p><ul><li><code>safe_resolve(base, path)</code> — Validates path stays within base directory</li><li><code>safe_join(base, *parts)</code> — Safe path joining</li><li><code>safe_open(base, path)</code> — Safe file open</li></ul><h2 id="audit-results-march-2026" tabindex="-1">Audit Results (March 2026) <a class="header-anchor" href="#audit-results-march-2026" aria-label="Permalink to &quot;Audit Results (March 2026)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scan</th><th>Result</th></tr></thead><tbody><tr><td>Snyk Code (SAST)</td><td>✅ 0 medium+ issues</td></tr><tr><td>innerHTML grep scan</td><td>✅ 0 unescaped patterns</td></tr><tr><td>Secret scan</td><td>✅ 0 real issues (2 false positives in docs)</td></tr></tbody></table><h2 id="reporting-vulnerabilities" tabindex="-1">Reporting Vulnerabilities <a class="header-anchor" href="#reporting-vulnerabilities" aria-label="Permalink to &quot;Reporting Vulnerabilities&quot;">​</a></h2><p>If you discover a security vulnerability, please report it responsibly by opening a private issue on <a href="https://github.com/tody-agent/codymaster/security" target="_blank" rel="noreferrer">GitHub</a>.</p>',27)])])}const y=t(n,[["render",s]]);export{p as __pageData,y as default};
